import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.炽焰天穹专属能力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/炽焰天穹/2.炽焰天穹专属能力.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/炽焰天穹/2.炽焰天穹专属能力.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/炽焰天穹/2.炽焰天穹专属能力.md"};function _(o,b,d,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"_2-炽焰天穹专属能力",tabindex:"-1"},[p("2.炽焰天穹专属能力 "),r("a",{class:"header-anchor",href:"#_2-炽焰天穹专属能力","aria-label":'Permalink to "2.炽焰天穹专属能力"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="炽焰天穹专属能力" tabindex="-1">炽焰天穹专属能力 <a class="header-anchor" href="#炽焰天穹专属能力" aria-label="Permalink to &quot;炽焰天穹专属能力&quot;">​</a></h1><p>名词介绍：<br> 【心眼状态】：攻击时强制消耗一层，使这次攻击出目变为1.5倍（并且显而易见的多个1.5倍不会叠加处理）。一回合最多消耗两层【心眼状态】。<br> 【连击珠】：攻击时强制消耗一层，使这次攻击造成的最终伤害增加一倍。一回合最多消耗两层【连击珠】。<br> 【脆弱】：被攻击时如果存在易伤，则对应易伤的属性的攻击出目变为1.5倍，这一效果每轮只会触发一次，攻击者可自行选择是否触发。</p><p>特殊的是，无论是心眼还是连击珠，每个能力只能叠加1层，这意味着你需要多个提供心眼或连击珠的能力才能叠加两层。</p><p>希望探求者<br> C+1000<br> 描述：“我是■■……我是■■的希望……我要为同胞找到没有星癌体存在的星球……但是我却……”<br> 效果：你获得免疫不超过A级衰老与即死来源效果的能力。</p><p>射法八节<br> B+2000<br> 资源限制：使用弓箭且【吧唧-桐生美也】生效时可以使用<br> 使用动作：标准动作+移动动作+迅捷动作，随后以自由动作释放。<br> 描述：踏足。定身。搭箭。举弓。拉弓。瞄准。射箭。残心。正射必中！<br> 效果：<br> 你进行一次不能附带任何招式的普通远程攻击。<br> 这次攻击无视闪避防御，视为一个B级祝福来源的效果。<br> 这次攻击获得高速/破甲/破魔20（购买时自选其一），这些破防效果若在计算目标防御后仍有剩余，则剩余破防转为攻击检定上的等量修行加值。<br> 这次攻击提升两倍基础射程，但若你是使用步枪，狙击枪，则只能提升60米射程。<br> 这次攻击视为瞄准了两轮。</p><p>无中生有<br> B+3000<br> 使用动作：迅捷动作<br> 射程：15米内的一个友方单位（可选自己）<br> 效果：<br> “就此，契约生效！”你的目标获得一层【连击珠】，并在下一次攻击时获得1DP的士气加值，这一效果同时只能对一人生效。</p><p>炯眼模式<br> B+2500<br> 使用动作：迅捷动作<br> 影响范围：自身<br> 描述：磨刀霍霍，让自身处于心眼状态。<br> 效果：你获得一层【心眼状态】。</p><p>属性领域展开<br> B+2000<br> 使用动作：整轮动作<br> 持续时间：一场景<br> 影响范围：见效果<br> 效果：<br> 购买时从火、冰、雷、神圣、亵渎、物理中选择一种属性。<br> 进行一次攻击，以这次攻击的目标为中心（多目标则自行选择其一），展开半径40米的对应属性领域。领域范围内有属性对应的天象（火花、雪花、电荷、圣光、阴云、稻花），天象总是延迟一轮后才会实际生效。<br> 不论来源等级，后生效的领域总是替换掉先生效的领域。<br> 从属性领域中发出的攻击，不分敌我的，造成对应属性伤害的攻击造成的最终伤害增加一半，每个单位在每轮中只会获得一次这一效果提供的好处。</p><p>火-炎热环境，但DC提升至24。<br> 冰-大雪环境。<br> 电荷-领域中的单位在被命中时获得【雷电易伤1】，不会叠加。<br> 圣光-领域中的亮度等级提升1级。<br> 阴云-领域中的亮度等级下降1级。<br> 稻花-可以使领域中无支线等级的植物快速生长至体积10。</p><p>纯洁之吻<br> B+2000<br> 资源限制：使用冲锋枪、手枪、霰弹枪类武器<br> 使用动作：标准动作<br> 影响范围：武器射程范围锥形<br> 效果：<br> “欢迎来到晦暗的夜幕世界。”<br> 使影响范围内的指定一个敌人获得持续一轮的【脆弱】状态，和2点雷电能量伤害的易伤。<br> 随后，你对该范围内的敌人进行一次普通攻击检定，这次攻击的伤害类型变为雷电能量伤害。</p><p>霸道妄执我突迈进<br> B+2000<br> 使用动作：整轮动作<br> 描述：给予（单体）敌人威压使其脆弱，狠狠扔出大剑造成破坏。<br> 效果：<br> 结合在一次冲锋攻击中使用，在这次攻击前使目标获得持续一轮的【脆弱】状态和物理易伤6，在这次攻击中你的移动速度按+60米计算，即使这次冲锋移动后目标脱离攻击范围你也可以正常进行攻击。</p><p>三日月宗近+<br> B+2000<br> 资源限制：使用刀、剑类武器或可以造成穿刺类型伤害的武器<br> 使用动作：标准动作，并透支下回合的标准动作，这将如常占用下轮的标准动作转化上限与占用AP（显然的，你能在被透支过动作的回合中继续透支）。</p><p>直到你的下一个回合结束前，你失去所有基础防御，根据你最高内在强化等级。你在本轮攻击时获得9/12/15DP技艺加值（对应B/A/S级）。<br> 直到下一个回合开始前，你再失去所有其他防御，这些失去的防御每有6点，你在本轮攻击时获得1附加成功，最多获得传奇敏捷*内在最高支线等级（B3A4S5）个附加成功。<br> 随后，你进行一次普通近战攻击。在这次攻击中，你的出目增一半，并获得【湮灭】【幻灭】特性，每轮你只能使用一次这一效果。</p><p>红脸烙印<br> A+4000<br> 使用动作：自由动作<br> 影响范围：自身<br> 效果：<br> “下招定胜负！”你在本回合获得8AP，只能用于攻击或炽焰天穹下属技艺。你在本回合的下一次亵渎属性攻击获得12DP和3附加成功，技艺加值。</p><p>洞察真相+<br> A+5000<br> 资源限制：使用可以造成穿刺类型伤害的远程武器<br> 使用动作：标准动作<br> 影响范围：见下<br> 描述：使用揭露真相的锐利子弹贯穿敌方全体，造成贯通暴击！<br> 效果：<br> 你对前方最多等同敏感范围内（扇形）的所有敌方单位进行一次攻击，本次攻击附带【超级贯穿】，同时攻击出目增加一半处理（每轮只会生效一次），若你对攻击出目不满意则可以进行一次重骰，与原本的结果取高计算。在这次攻击中你可以任意留手，将最终伤害自行降低任意点。</p><p>天使之翼<br> A+4000<br> 资源限制：使用盾类装备时可以使用<br> 使用动作：整轮动作启动+反射动作调用<br> 持续时间：一轮<br> 影响范围：见效果<br> 描述：展开奇迹之盾将包括全体攻击在内的所有攻击向自身集中，并且令自己无效攻击。<br> 效果：整轮动作启动，在一轮之内，你可以无效一次对你的伤害（A级命运来源的无敌效果），你可以在自身的回合外以反射动作打断性的对半径100米范围内的友方进行一次全遮蔽。<br> 你可以在释放时额外消耗2意志力，使这次全遮蔽具有强拦截</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const A=e(s,[["render",_]]);export{f as __pageData,A as default};
